import { useState, useEffect, useRef } from 'react';
import io from 'socket.io-client';

let socket = null;

const SOCKET_URL = process.env.NEXT_PUBLIC_SOCKET_URL || '';

export default function PlayerPage() {
  const [gameState, setGameState] = useState(null);
  const [privateState, setPrivateState] = useState(null);
  const [myToken, setMyToken] = useState('');
  const [playerName, setPlayerName] = useState('');
  const [gameCode, setGameCode] = useState('');
  const [joinError, setJoinError] = useState('');
  const [joined, setJoined] = useState(false);
  const [currentQuestion, setCurrentQuestion] = useState(null);
  const [selectedAnswer, setSelectedAnswer] = useState(null);
  const [timeLeft, setTimeLeft] = useState(15);
  const [leaderboard, setLeaderboard] = useState([]);
  const [showPodium, setShowPodium] = useState(false);

  useEffect(() => {
    const urlParams = new URLSearchParams(window.location.search);
    const code = urlParams.get('code');
    if (code) setGameCode(code);

    if (!socket) {
      socket = io(SOCKET_URL || window.location.origin, {
        path: SOCKET_URL ? '/socket.io' : undefined,
      });
    }

    socket.on('connect', () => {
      console.log('Connected to server');
    });

    socket.on('game:state', (state) => {
      setGameState(state);
      if (state.question) {
        setCurrentQuestion(state.question);
      }
      if (state.leaderboard) {
        setLeaderboard(state.leaderboard);
      }
      if (state.state === 'finished') {
        setShowPodium(true);
      }
      if (state.state === 'lobby' || state.state === 'ready') {
        setShowPodium(false);
      }
    });

    socket.on('player:private', (state) => {
      setPrivateState(state);
    });

    socket.on('player:joined', ({ token }) => {
      setMyToken(token);
      setJoined(true);
      localStorage.setItem('ai_human_token', token);
    });

    socket.on('player:kicked', (reason) => {
      alert(reason);
      setJoined(false);
      setMyToken('');
      localStorage.removeItem('ai_human_token');
    });

    socket.on('player:error', (msg) => {
      setJoinError(msg);
    });

    const savedToken = localStorage.getItem('ai_human_token');
    const savedName = localStorage.getItem('ai_human_name');
    if (savedToken && savedName && code) {
      setPlayerName(savedName);
      socket.emit('player:reconnect', { token: savedToken });
      setJoined(true);
    }

    return () => {
      if (socket) {
        socket.off('connect');
        socket.off('game:state');
        socket.off('player:private');
        socket.off('player:joined');
        socket.off('player:kicked');
        socket.off('player:error');
      }
    };
  }, []);

  useEffect(() => {
    if (!gameState || gameState.state !== 'question') return;

    const interval = setInterval(() => {
      const remaining = Math.max(0, Math.ceil((gameState.questionEndsAt - Date.now()) / 1000));
      setTimeLeft(remaining);
      if (remaining <= 0) clearInterval(interval);
    }, 100);

    return () => clearInterval(interval);
  }, [gameState]);

  const handleJoin = () => {
    if (!gameCode || !playerName) {
      setJoinError('Моля, въведете код и име');
      return;
    }
    localStorage.setItem('ai_human_name', playerName);
    socket.emit('player:join', {
      token: myToken,
      name: playerName,
      gameCode: gameCode.toUpperCase()
    });
  };

  const handleAnswer = (choice) => {
    if (!joined || gameState?.state !== 'question') return;
    setSelectedAnswer(choice);
    socket.emit('player:answer', { choice });
  };

  if (!joined) {
    return (
      <div style={styles.container}>
        <div style={styles.joinCard}>
          <h1 style={styles.logo}>PGITECH</h1>
          <p style={styles.subtitle}>Въведи кода от учителя</p>
          <input
            type="text"
            placeholder="Код на играта"
            value={gameCode}
            onChange={(e) => setGameCode(e.target.value.toUpperCase())}
            style={styles.input}
            maxLength={6}
          />
          <input
            type="text"
            placeholder="Твоето име"
            value={playerName}
            onChange={(e) => setPlayerName(e.target.value)}
            style={styles.input}
            maxLength={20}
          />
          {joinError && <p style={styles.error}>{joinError}</p>}
          <button onClick={handleJoin} style={styles.primaryBtn}>
            Влез в играта
          </button>
        </div>
      </div>
    );
  }

  if (showPodium && gameState?.state === 'finished') {
    return (
      <div style={styles.container}>
        <div style={styles.podiumCard}>
          <h1 style={styles.logo}>Играта свърши!</h1>
          <h2>Твоят резултат: {privateState?.score || 0} точки</h2>
          <h3>Ранг: #{privateState?.rank || '-'}</h3>
          <div style={styles.topThree}>
            {leaderboard.slice(0, 3).map((player, i) => (
              <div key={i} style={styles.podiumPlace}>
                <div style={styles.podiumRank}>{i + 1}</div>
                <div style={styles.podiumName}>{player.name}</div>
                <div style={styles.podiumScore}>{player.score}</div>
              </div>
            ))}
          </div>
        </div>
      </div>
    );
  }

  if (!gameState || gameState.state === 'lobby') {
    return (
      <div style={styles.container}>
        <div style={styles.waitingCard}>
          <div style={styles.spinner}></div>
          <h2>Изчакване на играча...</h2>
          <p>Код: {gameCode}</p>
        </div>
      </div>
    );
  }

  if (gameState.state === 'ready') {
    return (
      <div style={styles.container}>
        <div style={styles.readyCard}>
          <h1 style={styles.logo}>PGITECH</h1>
          <h2>Играта започва скоро!</h2>
          <p>Брой въпроси: {gameState.totalQuestions}</p>
          <p>Играчи: {gameState.playersCount}</p>
          {privateState && (
            <div style={styles.myInfo}>
              <p>Твоето име: {playerName}</p>
              <p>Точки: {privateState.score}</p>
            </div>
          )}
        </div>
      </div>
    );
  }

  if (gameState.state === 'question' && currentQuestion) {
    const qType = currentQuestion.questionType || 'code';
    const progress = ((15 - timeLeft) / 15) * 100;

    return (
      <div style={styles.container}>
        <div style={styles.gameHeader}>
          <span>Въпрос {gameState.currentQuestionIndex + 1}/{gameState.totalQuestions}</span>
          <span style={{ color: timeLeft <= 5 ? '#ef4444' : '#10b981' }}>{timeLeft}с</span>
        </div>
        
        <div style={styles.timerBar}>
          <div style={{ ...styles.timerProgress, width: `${progress}%` }}></div>
        </div>

        <div style={styles.questionArea}>
          {qType === 'code' && (
            <div style={styles.codePanels}>
              <div style={styles.codePanel}>
                <h3 style={styles.codeTitle}>{currentQuestion.leftTitle || 'Ляв код'}</h3>
                <pre style={styles.codeBlock}>{currentQuestion.leftCode || 'Няма код'}</pre>
              </div>
              <div style={styles.codePanel}>
                <h3 style={styles.codeTitle}>{currentQuestion.rightTitle || 'Десен код'}</h3>
                <pre style={styles.codeBlock}>{currentQuestion.rightCode || 'Няма код'}</pre>
              </div>
            </div>
          )}
          
          {qType === 'multiple_choice' && (
            <div style={styles.questionText}>
              <h2>{currentQuestion.questionText}</h2>
            </div>
          )}
        </div>

        <div style={styles.answersGrid}>
          <button
            onClick={() => handleAnswer(0)}
            style={{
              ...styles.answerBtn,
              background: selectedAnswer === 0 ? '#ef4444' : '#374151'
            }}
            disabled={selectedAnswer !== null}
          >
            Лявата е от човек, дясната е ИИ
          </button>
          <button
            onClick={() => handleAnswer(1)}
            style={{
              ...styles.answerBtn,
              background: selectedAnswer === 1 ? '#3b82f6' : '#374151'
            }}
            disabled={selectedAnswer !== null}
          >
            Дясната е от човек, лявата е ИИ
          </button>
          <button
            onClick={() => handleAnswer(2)}
            style={{
              ...styles.answerBtn,
              background: selectedAnswer === 2 ? '#eab308' : '#374151'
            }}
            disabled={selectedAnswer !== null}
          >
            И двете са от човек
          </button>
          <button
            onClick={() => handleAnswer(3)}
            style={{
              ...styles.answerBtn,
              background: selectedAnswer === 3 ? '#22c55e' : '#374151'
            }}
            disabled={selectedAnswer !== null}
          >
            И двете са от ИИ
          </button>
        </div>

        <div style={styles.leaderboard}>
          <h3>Класиране</h3>
          {leaderboard.slice(0, 5).map((player, i) => (
            <div key={i} style={styles.leaderboardItem}>
              <span style={styles.rank}>#{i + 1}</span>
              <span style={styles.playerName}>{player.name}</span>
              <span style={styles.playerScore}>{player.score}т</span>
            </div>
          ))}
        </div>
      </div>
    );
  }

  if (gameState.state === 'pause' || gameState.state === 'reveal') {
    return (
      <div style={styles.container}>
        <div style={styles.pauseCard}>
          <h2>Следващ въпрос след...</h2>
          <div style={styles.pauseCountdown}>
            {Math.ceil((gameState.pauseEndsAt - Date.now()) / 1000)}
          </div>
          
          {privateState?.revealMessage && (
            <p style={styles.revealMessage}>{privateState.revealMessage}</p>
          )}
          
          <div style={styles.leaderboard}>
            <h3>Класиране</h3>
            {leaderboard.slice(0, 5).map((player, i) => (
              <div key={i} style={styles.leaderboardItem}>
                <span style={styles.rank}>#{i + 1}</span>
                <span style={styles.playerName}>{player.name}</span>
                <span style={styles.playerScore}>{player.score}т</span>
              </div>
            ))}
          </div>
        </div>
      </div>
    );
  }

  return (
    <div style={styles.container}>
      <div style={styles.waitingCard}>
        <h2>Loading...</h2>
      </div>
    </div>
  );
}

